// Get Ahrefs keyword data
const ahrefsData = $('Ahrefs Keywords').item.json;
const keywords = ahrefsData.keywords || [];

// Normalize CPC (Ahrefs returns cents) and handle null KD
const normalizedKeywords = keywords.map(k => ({
  keyword: k.keyword,
  volume: k.volume || 0,
  kd: k.difficulty !== null && k.difficulty !== undefined ? k.difficulty : 0,
  cpc: k.cpc || 0
}));

// Get Claude enrichment data
const claudeResponse = $('Claude Enrichment').item.json;
const content = claudeResponse.content?.[0]?.text || '{}';

let enrichment = {};
try {
  enrichment = JSON.parse(content);
} catch(e) {
  enrichment = {
    areaTypes: {},
    ymyl: { isYMYL: false, reason: 'Parse error — defaulting to non-YMYL' },
    benchmarks: { industry: 'Unknown', closeRate: 35, avgSaleValue: 1000, convRate: 2.5 }
  };
}

return {
  keywords: normalizedKeywords,
  areaTypes: enrichment.areaTypes || {},
  ymyl: enrichment.ymyl || { isYMYL: false },
  benchmarks: enrichment.benchmarks || null
};
